class Solution {
public:
    vector<int> gardenNoAdj(int n, vector<vector<int>>& paths) {
        vector<int> res(n, 0);
        vector<vector<int>> graph(n + 1);
        for (auto& p : paths) {
            graph[p[0]].push_back(p[1]);
            graph[p[1]].push_back(p[0]);
        }
        for (int i = 1; i <= n; ++i) {
            set<int> used;
            for (int j : graph[i]) {
                if (res[j - 1]) used.insert(res[j - 1]);
            }
            for (int j = 1; j <= 4; ++j) {
                if (!used.count(j)) {
                    res[i - 1] = j;
                    break;
                }
            }
        }
        return res;
    }
};
